Hi,

Seems to be an issue after:
https://reviews.freebsd.org/D6987

What happens if you compile a kernel without:
PMAP_LOCK(pmap);

and

PMAP_UNLOCK(pmap);


Index: sys/arm64/arm64/pmap.c
===================================================================
--- sys/arm64/arm64/pmap.c	(revision 352210)
+++ sys/arm64/arm64/pmap.c	(working copy)
@@ -5810,7 +5810,7 @@
 	case ISS_DATA_DFSC_TF_L1:
 	case ISS_DATA_DFSC_TF_L2:
 	case ISS_DATA_DFSC_TF_L3:
-		PMAP_LOCK(pmap);
+		// PMAP_LOCK(pmap);
 		/* Ask the MMU to check the address */
 		intr = intr_disable();
 		if (pmap == kernel_pmap)
@@ -5818,7 +5818,7 @@
 		else
 			par = arm64_address_translate_s1e0r(far);
 		intr_restore(intr);
-		PMAP_UNLOCK(pmap);
+		// PMAP_UNLOCK(pmap);

 		/*
 		 * If the translation was successful the address was invalid
